class Solution:
    def largestWord(self, word: str, numFriends: int) -> str:
        def backtrack(start, path):
            if len(path) == numFriends:
                result.add(''.join(path))
                return
            for end in range(start + 1, len(word) + 1):
                backtrack(end, path + [word[start:end]])

        result = set()
        backtrack(0, [])
        return max(result)
```
